// Extract 'reply' from agent output (handles both JSON string and object)
const raw = $input.item.json.output ?? '';
let reply = '';
try {
  const parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
  reply = parsed.reply ?? parsed.response ?? parsed.output ?? String(raw);
} catch {
  // Agent responded as plain text — use directly
  reply = String(raw).replace(/^\{[\s\S]*"reply"\s*:\s*"|"\s*\}$/g, '');
}
return { reply };
